fn prune_stale_client_views(views: &mut HashMap<String, ClientView>) {
    let now = now_unix_millis();
    views.retain(|_, view| now.saturating_sub(view.updated_at_ms) <= CLIENT_VIEW_STALE_TIMEOUT_MS);
}

